{
  "summary": "This paper presents CORA, a unified multilingual open question answering system that integrates cross-lingual dense passage retrieval and answer generation without relying on translation pipelines. Through iterative training and data expansion leveraging Wikipedia language links and Wikidata, CORA achieves state-of-the-art results on two multilingual QA benchmarks across 26 languages, including unseen languages, demonstrating strong cross-lingual generalization.",
  "strengths": [
    {
      "point": "Unified multilingual QA model without translation reliance",
      "evidence": "CORA performs cross-lingual dense passage retrieval and answer generation directly in multiple languages without external machine translation or language-specific retrieval modules."
    },
    {
      "point": "Iterative training and cross-lingual data expansion",
      "evidence": "The method leverages Wikipedia language links and Wikidata to automatically expand training data, improving retrieval and generation for low-resource and unseen languages without additional human annotation."
    },
    {
      "point": "Strong empirical performance across diverse languages",
      "evidence": "CORA achieves significant improvements of 21.4 F1 on XOR-TYDI QA and 4.9 F1 on MKQA, including gains on 9 unseen languages, outperforming prior state-of-the-art methods."
    },
    {
      "point": "Comprehensive analysis and human evaluation",
      "evidence": "The paper includes ablations showing the importance of iterative training and cross-lingual data, human evaluation confirming 96% relevance of retrieved passages, and error analyses identifying dominant retrieval errors."
    },
    {
      "point": "Public release of code and models",
      "evidence": "Authors commit to releasing code and models to facilitate further research in multilingual open QA."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison with recent strong multilingual dense retrieval baselines",
      "evidence": "The paper lacks explicit experimental comparisons or ablation studies against recent models like mContriever or multilingual DPR variants beyond cited baselines."
    },
    {
      "point": "Lack of quantitative analysis and justification for iterative training",
      "evidence": "No performance curves per iteration, error rates of auto-labeled data, or sensitivity analyses on seed data size and quality are provided to validate the iterative training approach."
    },
    {
      "point": "Missing details on language-specific tokenization and embedding alignment",
      "evidence": "The paper does not discuss handling of script differences, subword vocabularies, or tokenization effects on embedding alignment and retrieval/generation errors."
    },
    {
      "point": "Unclear baseline implementation and fairness of comparisons",
      "evidence": "It is not stated whether baselines were retrained on the same data and evaluation protocols, nor are statistical significance tests or confidence intervals reported."
    },
    {
      "point": "Evaluation metrics limited to F1 without retrieval or generation quality breakdown",
      "evidence": "Metrics like Exact Match, retrieval recall@k, MRR, BLEU, ROUGE, or human fluency ratings are missing, limiting understanding of component contributions."
    },
    {
      "point": "Absence of detailed per-language error analysis and typological correlations",
      "evidence": "No quantitative error breakdowns, confusion matrices, or analyses correlating errors with language typology, script, or resource availability are presented."
    },
    {
      "point": "Reproducibility hindered by missing critical hyperparameters and training details",
      "evidence": "Key hyperparameters for mDPR and mGEN, hardware specs, training time, and checkpoint selection criteria are omitted."
    },
    {
      "point": "Insufficient specification of data expansion and automatic labeling procedures",
      "evidence": "No precise definitions or algorithmic descriptions of answer matching criteria, filtering heuristics, or use of Wikipedia/Wikidata mappings are provided."
    },
    {
      "point": "Ambiguity in cross-lingual retrieval indexing and scoring mechanisms",
      "evidence": "It is unclear whether a joint or language-specific index is used, how language identifiers affect retrieval scoring, or how retrieval biases are handled."
    },
    {
      "point": "Limited analysis of generalization to unseen languages",
      "evidence": "No linguistic analyses or ablations on script overlap or typological distance are provided to explain zero-shot performance."
    },
    {
      "point": "No discussion of computational efficiency, scalability, or inference latency",
      "evidence": "The paper omits measurements of index size, retrieval speed, generation time, and practical deployment considerations."
    },
    {
      "point": "Potential bias and coverage issues from Wikipedia and Wikidata data sources",
      "evidence": "No empirical evaluation of topic or language coverage disparities and their impact on fairness or performance is included."
    },
    {
      "point": "Generalisability restricted to Wikipedia domain without domain adaptation analysis",
      "evidence": "No experiments or discussion on performance in non-Wikipedia domains or robustness to other text genres."
    },
    {
      "point": "No exploration of transferability to related tasks beyond open QA",
      "evidence": "The paper does not assess applicability to tasks like summarization, fact verification, or cross-lingual IR."
    },
    {
      "point": "Lack of qualitative examples and visualizations",
      "evidence": "No concrete retrieval or generation examples, visualizations of retrieval scores, or case studies are provided."
    },
    {
      "point": "No analysis of passage length or document structure variability effects",
      "evidence": "The impact of varying passage lengths or Wikipedia edition differences on performance is not discussed."
    },
    {
      "point": "Unclear handling of ambiguous or multi-hop questions",
      "evidence": "The model's capability or limitations on multi-hop or complex reasoning questions are not addressed."
    },
    {
      "point": "No analysis of noise impact from incomplete Wikipedia language links",
      "evidence": "The effect of noisy or incomplete inter-language links on data expansion quality and downstream performance is not quantified."
    },
    {
      "point": "Potential overfitting to Wikipedia’s formal style and content",
      "evidence": "No discussion or evaluation on robustness to informal or conversational text domains."
    },
    {
      "point": "Absence of model calibration or confidence estimation analysis",
      "evidence": "No evaluation of retrieval or generation confidence calibration or uncertainty quantification is reported."
    }
  ],
  "questions": [
    {
      "question": "How does CORA compare quantitatively to recent strong multilingual dense retrieval models like mContriever or multilingual DPR variants?",
      "motivation": "Establishing novelty and effectiveness requires direct comparison to state-of-the-art retrieval baselines."
    },
    {
      "question": "What is the convergence behavior and robustness of the iterative training and data expansion procedure?",
      "motivation": "Understanding whether iterative training yields consistent gains or risks reinforcing biases is critical for method validation."
    },
    {
      "question": "How do language-specific tokenization and script differences affect embedding alignment and retrieval/generation performance?",
      "motivation": "Clarifying these aspects is important for assessing model generalization across typologically diverse languages."
    },
    {
      "question": "Are the reported baseline results obtained from retrained models under identical conditions, and are improvements statistically significant?",
      "motivation": "Ensuring fair and rigorous evaluation supports the credibility of claimed performance gains."
    },
    {
      "question": "Can the authors provide detailed per-language error analyses and correlations with language typology or resource availability?",
      "motivation": "Such analyses would deepen understanding of strengths and weaknesses across languages and guide future improvements."
    },
    {
      "question": "What are the computational costs, scalability limits, and inference latencies of CORA in practical deployment scenarios?",
      "motivation": "Assessing efficiency is essential for real-world applicability of large multilingual QA systems."
    },
    {
      "question": "How robust is CORA to noisy or incomplete Wikipedia language links used in data expansion?",
      "motivation": "Quantifying noise impact informs reliability and potential improvements in data mining."
    },
    {
      "question": "Does CORA generalize beyond Wikipedia domains and transfer to related tasks like summarization or fact verification?",
      "motivation": "Evaluating generalizability and transferability broadens the model's utility and research impact."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
